CREATE OR REPLACE FUNCTION fpa_acc_lon_coll_amount (as_conno char,as_colltype char) RETURNS bigint AS $body$
DECLARE

  cur_coll CURSOR FOR
  SELECT used_amount
  from sc_lon_m_contract_coll
  where (loan_contract_no = as_conno)
  and (collateral_type_code = as_colltype);
  type tabrowi_coll is table of cur_coll%rowtype index by integer;
  ltabrowi_coll tabrowi_coll;

  ldc_return bigint := 0;
  li_count integer;
BEGIN
  open cur_coll;
  fetch cur_coll bulk collect into ltabrowi_coll;
  close cur_coll;
  li_count := ltabrowi_coll.count;
  for i in 1..li_count loop
    if as_colltype = '01' then --คนค้ำ
      ldc_return := ldc_return + 1;
    else
      ldc_return := ldc_return + ltabrowi_coll[i].used_amount;
    end if;
  end loop;

  return coalesce(ldc_return,0);
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
